import * as React from 'react';
import { useControlledState } from '@universe-design/react-utilities';
import { DateCalendarUI, isDateValueEqual } from './DateCalendarUI';
import type { DateCalendarUIProps } from './interface';
import { forwardHTMLRef } from '../../../util/forwardRef';

/**
 * @docgen
 * @public
 * DateCalendar 组件的属性
 */
export type DateCalendarProps<DateType = moment.Moment> = Omit<
  DateCalendarUIProps,
  'selectedDates' | 'selectedRange'
> & {
  /**
   * 选中值（受控）
   */
  value?: DateType;
  /**
   * 默认选中值
   */
  defaultValue?: DateType;
  /**
   * 选中值发生变化的回调
   */
  onChange?: (v: DateType | undefined) => void;
};

/**
 * @public
 * 带单选逻辑的日期面板
 */
export const DateCalendar = forwardHTMLRef<DateCalendarProps, 'div'>((props, ref) => {
  const { value: valueProp, defaultValue, onChange, onSelect, ...restProps } = props;

  const [value, setValue] = useControlledState(defaultValue, valueProp, {
    isEqual: isDateValueEqual,
    onChange,
  });

  const selectedDates = value ? [value] : [];

  const onDateSelect = (v: moment.Moment) => {
    onSelect?.(v);
    setValue(v);
  };

  return <DateCalendarUI ref={ref} {...restProps} onSelect={onDateSelect} selectedDates={selectedDates} />;
});
